        BackgroundNode("home asa", timer: null, layers: null, transitionType: "diss", animation: null, repeatCount: null),
        SayNode(character: null, dialogue: "我遵循着母亲的嘱咐，背上了书包。", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 39, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
