        PlaySoundNode("bird", loop: false),
        SayNode(character: null, dialogue: "伴随着小鸟的鸣叫声，我缓缓沿着道路前进。", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 50, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        BackgroundNode("to school", timer: null, layers: null, transitionType: null, animation: null, repeatCount: null),
        NvlMovieNode(),
