        SayNode(character: null, dialogue: "每节课老师都会花后一半时间给四年级的我教书，前一半时间则是给了三年级的剩下三个人。", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 71, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
