        SayNode(character: null, dialogue: "我是四年级，她则是三年级的年纪，比我小一个年级，至于年龄，却是和我同岁。", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 98, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
