        BackgroundNode("ha", timer: null, layers: null, transitionType: null, animation: null, repeatCount: null),
        SayNode(character: "xnan", dialogue: "「这个是树叶，哈哈，为什么这个也是食材，因为这才环保嘛，电视上不是老说什么环保环保嘛，连带盘子一起吃掉，连光盘行动都不需要了。」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 354, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
        BackgroundNode("ichigo", timer: null, layers: null, transitionType: null, animation: null, repeatCount: null),
        SayNode(character: "xnan", dialogue: "「别的我不敢保证能不能吃，这个是绝对不能吃的！这个是蛇莓，听说蛇会在上面留口水，所以吃了有毒，只能摘但是别吃！」", dialogueTag: null, tailCharacter: null, tailPose: null, tailExpression: null, tailAnimation: null, tailRepeatCount: null, sourceFile: null, sourceLine: 356, pose: null, expression: null, position: null, animation: null, repeatCount: null, startExpression: null, switchDelay: null, endExpression: null),
